class Solution {
    public String crackSafe(int n, int k) {
        int target = (int) Math.pow(k, n);
        boolean[] visited = new boolean[target];
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < n; i++) {
            sb.append('0');
        }
        int start = 0;
        for (int i = 0; i < target; i++) {
            for (int j = 0; j < k; j++) {
                int t = (start * 10 + j) % target;
                if (!visited[t]) {
                    visited[t] = true;
                    start = t;
                    sb.append(j);
                    break;
                }
            }
        }
        return sb.toString();
    }
}
